import React, { Component } from 'react';


export default class AnalogSub extends Component {
    constructor(props) {
        super(props);
        this.state = {
                    title: props.title,
                    pic: props.pic, 
                    link: props.link
                    };
    }

    render() {
        const { title, pic, link } = this.state;
        return (
            <div>
                <h3>{title}</h3>
                <img src={pic} alt={title} />
                <p><a href={link}>Youtube Link</a></p>
            </div>

        )
    }

};
